const srcItem = $input.first();
const raw = srcItem?.json ?? {};
const root = Array.isArray(raw) ? raw[0] : raw;

const payload =
  (Array.isArray(root?.payload) && root.payload) ||
  (Array.isArray(root?.messages) && root.messages) ||
  (Array.isArray(root?.data) && root.data) ||
  (Array.isArray(root) && root) ||
  [];

const tz = 'America/Sao_Paulo';
const dtDate = new Intl.DateTimeFormat('pt-BR', { timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit' });
const dtTime = new Intl.DateTimeFormat('pt-BR', { timeZone: tz, hour: '2-digit', minute: '2-digit' });

function toMs(c) {
  if (!c) return null;
  if (typeof c === 'number') { const n = Math.abs(c); return n > 1e12 ? n : n * 1000; }
  const ms = Date.parse(c); return Number.isNaN(ms) ? null : ms;
}
function stripHtml(s) {
  return String(s ?? '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>\s*<p>/gi, '\n\n')
    .replace(/<\/?(p|strong|b|em|i|span|div|blockquote)[^>]*>/gi, '')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').trim();
}
function normalize(s) {
  return stripHtml(s).replace(/\r\n/g, '\n').replace(/[ \t]+\n/g, '\n').replace(/\n{3,}/g, '\n\n').trim();
}
function sender(m) {
  if (m?.message_type === 2) return 'Sistema';
  const t = String(m?.sender?.type || '').toLowerCase();
  if (t === 'contact') return 'Cliente';
  if (t === 'user') return 'Agente';
  if (m?.message_type === 0) return 'Cliente';
  if (m?.message_type === 1) return 'Agente';
  return 'Desconhecido';
}
function isNoise(t) {
  const s = t.toLowerCase();
  return ['assigned to','automation system added','conversation was marked resolved','conversation was reopened','self-assigned','changed the assignee','added bot_active','marked resolved','reopened'].some(p => s.includes(p));
}
function isRelevant(t) {
  const s = t.toLowerCase();
  return s.includes('fechado_por_inatividade') || s.includes('timeout') || s.includes('inatividade') || s.includes('criado como ticket');
}

const msgs = payload
  .filter(m => !m?.private)
  .map(m => ({ id: Number(m?.id ?? 0), ms: toMs(m?.created_at), type: m?.message_type, sender: sender(m), text: normalize(m?.content ?? '') }))
  .filter(m => m.ms && m.text)
  .sort((a, b) => (a.ms - b.ms) || (a.id - b.id));

const normal = [], activities = [];
for (const m of msgs) {
  if (m.type === 2) {
    if (isNoise(m.text) && !isRelevant(m.text)) continue;
    activities.push(m);
  } else normal.push(m);
}

let out = '', lastDate = null;
for (const m of normal) {
  const d = dtDate.format(new Date(m.ms));
  if (d !== lastDate) { if (out) out += '\n\n'; out += `${d}\n`; lastDate = d; }
  out += `${dtTime.format(new Date(m.ms))}  ${m.sender}: ${m.text}\n`;
}
out = out.trim();

if (activities.length) {
  let act = '', lastActDate = null;
  for (const m of activities) {
    const d = dtDate.format(new Date(m.ms));
    if (d !== lastActDate) { act += (act ? '\n' : '') + `${d}\n`; lastActDate = d; }
    act += `${dtTime.format(new Date(m.ms))}  Sistema: ${m.text}\n`;
  }
  out += `\n\nAtividades do sistema\n${act.trim()}`;
}

function esc(s) { return String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
const messages_text = esc(out).replace(/\n/g, '<br>');
return [{ json: { messages_text, messages_plain: out } }];

